UPDATE t_p28211681_photo_secure_web.legal_documents
SET content = REPLACE(
    content,
    '<p>5.10. Энергия расходуется по мере использования соответствующих функций согласно действующим тарифам списания, указанным на Сайте/в ЛК. Неизрасходованный остаток Энергии сохраняется на балансе Заказчика в течение срока действия аккаунта. Курс пополнения и стоимость функций в Энергии могут изменяться с публикацией на Сайте, без ухудшения условий уже приобретённого остатка.</p>',
    '<p>5.10. Энергия расходуется по мере использования соответствующих функций согласно действующим тарифам списания, указанным на Сайте/в ЛК. Неизрасходованный остаток Энергии сохраняется на балансе Заказчика в течение срока действия аккаунта. Курс пополнения и стоимость функций в Энергии могут изменяться с публикацией на Сайте, без ухудшения условий уже приобретённого остатка.</p>'
    || '<p>5.11. Неизрасходованный остаток Энергии не подлежит возврату или обмену на денежные средства, поскольку Энергия не является денежным средством или электронным средством платежа (п. 5.8). При добровольном удалении Заказчиком аккаунта, а также при блокировке/прекращении доступа по основаниям, предусмотренным настоящей Офертой (нарушение закона, Оферты или прав третьих лиц), неизрасходованный остаток Энергии аннулируется (сгорает) без компенсации.</p>'
    || '<p>5.12. Положения п. 5.11 не ограничивают право Заказчика‑потребителя на возврат денежных средств за фактически не оказанные услуги в порядке раздела 10 настоящей Оферты и применимого законодательства РФ (в частности, ст. 32 Закона «О защите прав потребителей»).</p>'
)
WHERE slug = 'offer';